(126, 1, '2022-08-08 19:07:57', '2022-08-08 16:07:57', '<!-- wp:acf/hero {\"id\":\"block_62eec4467b0c9\",\"name\":\"acf/hero\",\"data\":{\"hero_title\":\"\\u003cspan\\u003eЭковата «ВАТЭКО» — \\u003c/span\\u003e\\r\\nбезопасный утеплитель\",\"_hero_title\":\"field_hero_hero_title\",\"hero_image\":13,\"_hero_image\":\"field_hero_hero_image\",\"hero_file\":12,\"_hero_file\":\"field_hero_hero_file\",\"hero_text\":\"Экологичный строительный материал, простой \\r\\nв работе и обладающий уникальными тепло- \\r\\nи звукоизоляционными свойствами\",\"_hero_text\":\"field_hero_hero_text\",\"hero_url\":\"\",\"_hero_url\":\"field_hero_hero_url\"},\"align\":\"\",\"mode\":\"auto\"} /-->\n\n<!-- wp:acf/about {\"id\":\"block_62eec44b7b0cc\",\"name\":\"acf/about\",\"data\":{\"about_title\":\"Что такое эковата \\u003cspan\\u003e«Ватэко»?\\u003c/span\\u003e\",\"_about_title\":\"field_about_about_title\",\"about_subtitle\":\"Это лёгкий волокнистый материал \\r\\nсерого цвета. \",\"_about_subtitle\":\"field_about_about_subtitle\",\"about_text\":\"Эковата на 82% состоит из переработанной бумаги и на 18% —\\r\\nиз природных антисептиков и огнезащитных компонентов,\\r\\nчто делает её безопасной для людей и окружающей среды.\\r\\n\\r\\nВату используют для бесшовного утепления домов,\\r\\nмансард, ангаров и других сооружений.\",\"_about_text\":\"field_about_about_text\",\"about_image\":16,\"_about_image\":\"field_about_about_image\"},\"align\":\"\",\"mode\":\"auto\"} /-->\n\n<!-- wp:acf/products {\"id\":\"block_62eec44d7b0cd\",\"name\":\"acf/products\",\"data\":{\"products_title\":\"Наша продукция\",\"_products_title\":\"field_products_products_title\"},\"align\":\"\",\"mode\":\"auto\"} /-->\n\n<!-- wp:acf/stats {\"id\":\"block_62efa007ecdfa\",\"name\":\"acf/stats\",\"data\":{\"stats_title\":\"Ватэко в цифрах\",\"_stats_title\":\"field_stats_stats_title\",\"stats_list_0_stats_item_title\":\"25 лет\",\"_stats_list_0_stats_item_title\":\"field_stats_stats_list_stats_item_title\",\"stats_list_0_stats_item_text\":\"материал сохраняет \\u003cstrong\\u003eтепло- \\r\\nи звукоизоляционные\\u003c/strong\\u003e свойства\",\"_stats_list_0_stats_item_text\":\"field_stats_stats_list_stats_item_text\",\"stats_list_1_stats_item_title\":\"65 ДБ\",\"_stats_list_1_stats_item_title\":\"field_stats_stats_list_stats_item_title\",\"stats_list_1_stats_item_text\":\"степень \\u003cstrong\\u003eзвукоизоляции\\u003c/strong\\u003e стены, \\r\\nутеплённой эковатой\",\"_stats_list_1_stats_item_text\":\"field_stats_stats_list_stats_item_text\",\"stats_list_2_stats_item_title\":\"На 25%\",\"_stats_list_2_stats_item_title\":\"field_stats_stats_list_stats_item_title\",\"stats_list_2_stats_item_text\":\"\\u003cstrong\\u003eснижает затраты\\u003c/strong\\u003e на обогрев\\r\\nпомещения\",\"_stats_list_2_stats_item_text\":\"field_stats_stats_list_stats_item_text\",\"stats_list\":3,\"_stats_list\":\"field_stats_stats_list\"},\"align\":\"\",\"mode\":\"auto\"} /-->\n\n<!-- wp:acf/calc {\"id\":\"block_62efaa5a354ab\",\"name\":\"acf/calc\",\"data\":{\"calc_title\":\"Рассчитать количество \\u003cspan\\u003eэковаты\\u003c/span\\u003e\",\"_calc_title\":\"field_calc_calc_title\",\"items\":\"\",\"_items\":\"field_calc_items\"},\"align\":\"\",\"mode\":\"auto\"} /-->\n\n<!-- wp:acf/advantages {\"id\":\"block_62efb901c8ff8\",\"name\":\"acf/advantages\",\"data\":{\"advantages_title\":\"\\u003cspan\\u003eПреимущества\\u003c/span\\u003e эковаты “Ватэко”\",\"_advantages_title\":\"field_advantages_advantages_title\",\"advantages_icon\":93,\"_advantages_icon\":\"field_advantages_advantages_icon\",\"list_0_list_icon\":94,\"_list_0_list_icon\":\"field_advantages_list_list_icon\",\"list_0_list_title\":\"Воздухопроницаемость\",\"_list_0_list_title\":\"field_advantages_list_list_title\",\"list_0_list_text\":\"Не имеет запаха и не пылит. Не содержит \\r\\nлетучих химикатов, не вызывает аллергии.\",\"_list_0_list_text\":\"field_advantages_list_list_text\",\"list_1_list_icon\":95,\"_list_1_list_icon\":\"field_adva