(139, 1, '2022-08-08 23:29:56', '2022-08-08 20:29:56', '<!-- wp:acf/hero {\"id\":\"block_62eec4467b0c9\",\"name\":\"acf/hero\",\"data\":{\"hero_title\":\"\\u003cspan\\u003eЭковата «ВАТЭКО» — \\u003c/span\\u003e\\r\\nбезопасный утеплитель\",\"_hero_title\":\"field_hero_hero_title\",\"hero_image\":13,\"_hero_image\":\"field_hero_hero_image\",\"hero_file\":12,\"_hero_file\":\"field_hero_hero_file\",\"hero_text\":\"Экологичный строительный материал, простой \\r\\nв работе и обладающий уникальными тепло- \\r\\nи звукоизоляционными свойствами\",\"_hero_text\":\"field_hero_hero_text\",\"hero_url\":\"\",\"_hero_url\":\"field_hero_hero_url\"},\"align\":\"\",\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/about {\"id\":\"block_62eec44b7b0cc\",\"name\":\"acf/about\",\"data\":{\"about_title\":\"Что такое эковата \\u003cspan\\u003e«Ватэко»?\\u003c/span\\u003e\",\"_about_title\":\"field_about_about_title\",\"about_subtitle\":\"Это лёгкий волокнистый материал \\r\\nсерого цвета. \",\"_about_subtitle\":\"field_about_about_subtitle\",\"about_text\":\"Эковата на 82% состоит из переработанной бумаги и на 18% —\\r\\nиз природных антисептиков и огнезащитных компонентов,\\r\\nчто делает её безопасной для людей и окружающей среды.\\r\\n\\r\\nВату используют для бесшовного утепления домов,\\r\\nмансард, ангаров и других сооружений.\",\"_about_text\":\"field_about_about_text\",\"about_image\":16,\"_about_image\":\"field_about_about_image\"},\"align\":\"\",\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/products {\"id\":\"block_62eec44d7b0cd\",\"name\":\"acf/products\",\"data\":{\"products_title\":\"Наша продукция\",\"_products_title\":\"field_products_products_title\"},\"align\":\"\",\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/stats {\"id\":\"block_62efa007ecdfa\",\"name\":\"acf/stats\",\"data\":{\"stats_title\":\"Ватэко в цифрах\",\"_stats_title\":\"field_stats_stats_title\",\"stats_list_0_stats_item_title\":\"25 лет\",\"_stats_list_0_stats_item_title\":\"field_stats_stats_list_stats_item_title\",\"stats_list_0_