622,14.403,4.622,12 s0.009-2.688,0.052-3.637c0.04-0.877,0.187-1.354,0.31-1.671c0.163-0.42,0.358-0.72,0.673-1.035 c0.315-0.315,0.615-0.51,1.035-0.673c0.317-0.123,0.794-0.27,1.671-0.31C9.312,4.631,9.597,4.622,12,4.622 M12,3 C9.556,3,9.249,3.01,8.289,3.054C7.331,3.098,6.677,3.25,6.105,3.472C5.513,3.702,5.011,4.01,4.511,4.511 c-0.5,0.5-0.808,1.002-1.038,1.594C3.25,6.677,3.098,7.331,3.054,8.289C3.01,9.249,3,9.556,3,12c0,2.444,0.01,2.751,0.054,3.711 c0.044,0.958,0.196,1.612,0.418,2.185c0.23,0.592,0.538,1.094,1.038,1.594c0.5,0.5,1.002,0.808,1.594,1.038 c0.572,0.222,1.227,0.375,2.185,0.418C9.249,20.99,9.556,21,12,21s2.751-0.01,3.711-0.054c0.958-0.044,1.612-0.196,2.185-0.418 c0.592-0.23,1.094-0.538,1.594-1.038c0.5-0.5,0.808-1.002,1.038-1.594c0.222-0.572,0.375-1.227,0.418-2.185 C20.99,14.751,21,14.444,21,12s-0.01-2.751-0.054-3.711c-0.044-0.958-0.196-1.612-0.418-2.185c-0.23-0.592-0.538-1.094-1.038-1.594 c-0.5-0.5-1.002-0.808-1.594-1.038c-0.572-0.222-1.227-0.375-2.185-0.418C14.751,3.01,14.444,3,12,3L12,3z M12,7.378 c-2.552,0-4.622,2.069-4.622,4.622S9.448,16.622,12,16.622s4.622-2.069,4.622-4.622S14.552,7.378,12,7.378z M12,15 c-1.657,0-3-1.343-3-3s1.343-3,3-3s3,1.343,3,3S13.657,15,12,15z M16.804,6.116c-0.596,0-1.08,0.484-1.08,1.08 s0.484,1.08,1.08,1.08c0.596,0,1.08-0.484,1.08-1.08S17.401,6.116,16.804,6.116z\"></path></svg></a></li>\n 	<li class=\"wp-social-link wp-social-link-linkedin wp-block-social-link\"><a href=\"#\" aria-label=\"LinkedIn: #\" class=\"wp-block-social-link-anchor\"> <svg width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" version=\"1.1\" xmlns=\"http://www.w3.org/2000/svg\" role=\"img\" aria-hidden=\"true\" focusable=\"false\"><path d=\"M19.7,3H4.3C3.582,3,3,3.582,3,4.3v15.4C3,20.418,3.582,21,4.3,21h15.4c0.718,0,1.3-0.582,1.3-1.3V4.3 C21,3.582,20.418,3,19.7,3z M8.339,18.338H5.667v-8.59h2.672V18.338z M7.004,8.574c-0.857,0-1.549-0.694-1.549-1.548 c0-0.855,0.691-1.548,1.549-1.548c0.854,0,1.547,0.694,1.547,1.548C8.551,7.881,7.858,8.574,7.004,8.574z M18.339,18.338h-2.669 v-4.177c0-0.996-0.017-2.278-1.387-2.278c-1.389,0-1.601,1.086-1.601,2.206v4.249h-2.667v-8.59h2.559v1.174h0.037 c0.356-0.675,1.227-1.387,2.526-1.387c2.703,0,3.203,1.779,3.203,4.092V18.338z\"></path></svg></a></li>\n 	<li class=\"wp-social-link wp-social-link-youtube wp-block-social-link\"><a href=\"#\" aria-label=\"YouTube: #\" class=\"wp-block-social-link-anchor\"> <svg width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" version=\"1.1\" xmlns=\"http://www.w3.org/2000/svg\" role=\"img\" aria-hidden=\"true\" focusable=\"false\"><path d=\"M21.8,8.001c0,0-0.195-1.378-0.795-1.985c-0.76-0.797-1.613-0.801-2.004-0.847c-2.799-0.202-6.997-0.202-6.997-0.202 h-0.009c0,0-4.198,0-6.997,0.202C4.608,5.216,3.756,5.22,2.995,6.016C2.395,6.623,2.2,8.001,2.2,8.001S2,9.62,2,11.238v1.517 c0,1.618,0.2,3.237,0.2,3.237s0.195,1.378,0.795,1.985c0.761,0.797,1.76,0.771,2.205,0.855c1.6,0.153,6.8,0.201,6.8,0.201 s4.203-0.006,7.001-0.209c0.391-0.047,1.243-0.051,2.004-0.847c0.6-0.607,0.795-1.985,0.795-1.985s0.2-1.618,0.2-3.237v-1.517 C22,9.62,21.8,8.001,21.8,8.001z M9.935,14.594l-0.001-5.62l5.404,2.82L9.935,14.594z\"></path></svg></a></li>\n</ul>\nNo documentation is available.\n\n<hr class=\"wp-block-separator\">\n\n<h2>Table block</h2>\nInsert a table. Allows to specify table header and footer rows.\n<figure class=\"wp-block-table\">\n<table>\n<thead>\n<tr>\n<th>Header row</th>\n<th>Header label</th>\n<th>Header label</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Example</td>\n<td>of</td>\n<td>Table block</td>\n</tr>\n<tr>\n<td>with</td>\n<td>two</td>\n<td>rows</td>\n</tr>\n</tbody>\n<tfoot>\n<tr>\n<td>Footer row</td>\n<td>Footer label</td>\n<td>Footer label</td>\n</tr>\n</tfoot>\n</table>\n<figcaption>Table block caption</figcaption></figure>\nDocumentation and usage: <a href=\"https://wordpress.org/support/article/table-block/\">wordpress.org/support/article/table-block</a>\n\n<hr class=\"wp-block-separator\">\n\n<h2>Code block</h2>\nShow code in a code readable form.\n<pre class=\"wp-block-code\"><code>// code block example\n@media (min-width: 900px) and (max-width: 1219px) {\n  .visible-md-inline-block {\n    display: inline-block !important;\n  }\n}\nLorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.</code></pre>\nDocumentation and usage: <a href=\"https://wordpress.org/support/article/code-block/\">wordpress.org/support/article/code-block</a>\n\n<hr class=\"wp-block-separator\">\n\n<h2>Pullquote block</h2>\nUse to emphasise some text. Can be also used for important messages.\n<figure class=\"wp-block-pullquote\" style=\"border-color:#009cde\">\n<blockquote class=\"has-text-color has-grey-color\">Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.\n\n<cite>Pullquote block example</cite></blockquote>\n</figure>\nDocumentation and usage: <a href=\"https://wordpress.org/support/article/pullquote-block/\">wordpress.org/support/article/pullquote-block</a>\n\n<hr class=\"wp-block-separator\">\n\n<h2>Buttons block</h2>\nAdds button link(s) to the page. There’s plenty of style choices available: solid/outlined, squared/rounded. All with brand colours to choose from. Pay attention to the contrast and warning message will appear when contrast is not sufficieat.\n<div class=\"wp-container-4 wp-block-buttons\">\n<div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link has-darkblue-color has-white-background-color has-text-color has-background\">test</a></div>\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-black-color has-green-background-color has-text-color has-background no-border-radius\">buttons</a></div>\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-purple-background-color has-background\" style=\"border-radius:50px\">block</a></div>\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-black-color has-yellow-background-color has-text-color has-background\">🙂</a></div>\n</div>\nDocumentation not available.\n\n<hr class=\"wp-block-separator\">\n\n<h2>Columns block</h2>\nCreate more complex layouts using columns block. Number of predefined widths are available.\n<div class=\"wp-block-columns\">\n<div class=\"wp-block-column\">\n\nThree column block can contain other blocks so you can build complex layout for your pages if you need.\n\n</div>\n<div class=\"wp-block-column\">\n<figure class=\"wp-block-image size-large\"><img src=\"https://ctiss.site.hw.ac.uk/wp-content/uploads/sites/25/2020/07/research-ex-1-1024x683.jpg\" alt=\"\" class=\"wp-image-66\"></figure>\n</div>\n<div class=\"wp-block-column\">\n\nColumns are stacking when displayed on smaller screens. Bear that in mind so it still reads well as a single column.\n\n</div>\n</div>\nDocumentation and usage: <a href=\"https://wordpress.org/support/article/columns-block/\">wordpress.org/support/article/columns-block</a>\n\n<hr class=\"wp-block-separator\">\n\n<h2>Media Text block</h2>\nElement to show image and content side-by-side.\n<div class=\"wp-block-media-text alignwide is-stacked-on-mobile\">\n<figure class=\"wp-block-media-text__media\"><img src=\"https://ctiss.site.hw.ac.uk/wp-content/uploads/sites/25/2020/07/research-ex-1-1024x683.jpg\" alt=\"\" class=\"wp-image-66\"></figure>\n<div class=\"wp-block-media-text__content\">\n<p class=\"has-large-font-size\">Media text block</p>\n\n</div>\n</div>\nDocumentation and usage: <a href=\"https://wordpress.org/support/article/media-text-block/\">wordpress.org/support/article/media-text-block</a>\n\n<hr class=\"wp-block-separator\">\n\n<h2>Spacer block (just empty space)</h2>\nAdds blank space so content can get breathing space.\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\nDocumentation and usage: <a href=\"https://wordpress.org/support/article/spacer-block/\">wordpress.org/support/article/spacer-block</a>\n\n<hr class=\"wp-block-separator\">\n\n<h2>Gravity Forms block</h2>\nQuickly add existing form to the page. Forms are set in Forms menu and after are created can be included on the page using this block type.\n\n<hr class=\"wp-block-separator\">\n\n<h2>Page Break block (adds pagination)</h2>\nNothing on the second page – no need to click.\n\nSections divided here with the Separator block.\n<div class=\"page-links\">Pages: <span class=\"post-page-numbers current\" aria-current=\"page\">1</span> <a href=\"https://ctiss.site.hw.ac.uk/blocks/2/\" class=\"post-page-numbers\">2</a></div>', 'Test', '', 'inherit', 'closed', 'closed', '', '140-revision-v1', '', '', '2022-08-09 15:24:46', '2022-08-09 12:24:46', '', 140, 'http://vateko.loc/?p=142', 0, 'revision', '', 0),
(143, 1, '2022-08-09 18:33:20', '2022-08-09 15:33:20', '<!-- wp:acf/hero {\"id\":\"block_62eec4467b0c9\",\"name\":\"acf/hero\",\"data\":{\"hero_title\":\"\\u003cspan\\u003eЭковата «ВАТЭКО» — \\u003c/span\\u003e\\r\\nбезопасный утеплитель\",\"_hero_title\":\"field_hero_hero_title\",\"hero_image\":13,\"_hero_image\":\"field_hero_hero_image\",\"hero_video_id\":\"CyVuYAHiZb8\",\"_hero_video_id\":\"field_hero_hero_video_id\",\"hero_text\":\"Экологичный строительный материал, простой \\r\\nв работе и обладающий уникальными тепло- \\r\\nи звукоизоляционными свойствами\",\"_hero_text\":\"field_hero_hero_text\",\"hero_url\":\"\",\"_hero_url\":\"field_hero_hero_url\"},\"align\":\"\",\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/about {\"id\":\"block_62eec44b7b0cc\",\"name\":\"acf/about\",\"data\":{\"about_title\":\"Что такое эковата \\u003cspan\\u003e«Ватэко»?\\u003c/span\\u003e\",\"_about_title\":\"field_about_about_title\",\"about_subtitle\":\"Это лёгкий волокнистый материал \\r\\nсерого цвета. \",\"_about_subtitle\":\"field_about_about_subtitle\",\"about_text\":\"Эковата на 82% состоит из переработанной бумаги и на 18% —\\r\\nиз природных антисептиков и огнезащитных компонентов,\\r\\nчто делает её безопасной для людей и окружающей среды.\\r\\n\\r\\nВату используют для бесшовного утепления домов,\\r\\nмансард, ангаров и других сооружений.\",\"_about_text\":\"field_about_about_text\",\"about_image\":16,\"_about_image\":\"field_about_about_image\"},\"align\":\"\",\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/products {\"id\":\"block_62eec44d7b0cd\",\"name\":\"acf/products\",\"data\":{\"products_title\":\"Наша продукция\",\"_products_title\":\"field_products_products_title\"},\"align\":\"\",\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/stats {\"id\":\"block_62efa007ecdfa\",\"name\":\"acf/stats\",\"data\":{\"stats_title\":\"Ватэко в цифрах\",\"_stats_title\":\"field_stats_stats_title\",\"stats_list_0_stats_item_title\":\"25 лет\",\"_stats_list_0_stats_item_title\":\"field_stats_stats_list_stats_item_title\",\"stats_list_0_stats_item_text\":\"материал сохраняет \\u003cstrong\\u003eтепло- \\r\\nи звукоизоляционные\\u003c/strong\\u003e свойства\",\"_stats_list_0_stats_item_text\":\"field_stats_stats_list_stats_item_text\",\"stats_list_1_stats_item_title\":\"65 ДБ\",\"_stats_list_1_stats_item_title\":\"field_stats_stats_list_stats_item_title\",\"stats_list_1_stats_item_text\":\"степень \\u003cstrong\\u003eзвукоизоляции\\u003c/strong\\u003e стены, \\r\\nутеплённой эковатой\",\"_stats_list_1_stats_item_text\":\"field_stats_stats_list_stats_item_text\",\"stats_list_2_stats_item_title\":\"На 25%\",\"_stats_list_2_stats_item_title\":\"field_stats_stats_list_stats_item_title\",\"stats_list_2_stats_item_text\":\"\\u003cstrong\\u003eснижает затраты\\u003c/strong\\u003e на обогрев\\r\\nпомещения\",\"_stats_list_2_stats_item_text\":\"field_stats_stats_list_stats_item_text\",\"stats_list\":3,\"_stats_list\":\"field_stats_stats_list\"},\"align\":\"\",\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/calc {\"id\":\"block_62efaa5a354ab\",\"name\":\"acf/calc\",\"data\":{\"calc_title\":\"Рассчитать количество \\u003cspan\\u003eэковаты\\u003c/span\\u003e\",\"_calc_title\":\"field_calc_calc_title\",\"items\":\"\",\"_items\":\"field_calc_items\"},\"align\":\"\",\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/advantages {\"id\":\"block_62efb901c8ff8\",\"name\":\"acf/advantages\",\"data\":{\"advantages_title\":\"\\u003cspan\\u003eПреимущества\\u003c/span\\u003e эковаты “Ватэко”\",\"_advantages_title\":\"field_advantages_advantages_title\",\"advantages_icon\":93,\"_advantages_icon\":\"field_advantages_advantages_icon\",\"list_0_list_icon\":94,\"_list_0_list_icon\":\"field_advantages_list_list_icon\",\"list_0_list_title\":\"Воздухопроницаемость\",\"_list_0_list_title\":\"field_advantages_list_list_title\",\"list_0_list_text\":\"Не имеет запаха и не пылит. Не содержит \\r\\nлетучих химикатов, не вызывает аллергии.\",\"_list_0_list_text\":\"field_advantages_list_list_text\",\"list_1_list_icon\":95,\"_list_1