(178, 1, '2022-08-12 23:06:51', '2022-08-12 20:06:51', '<!-- wp:acf/hero {\"id\":\"block_62eec4467b0c9\",\"name\":\"acf/hero\",\"data\":{\"hero_title\":\"\\u003cspan\\u003eЭковата «ВАТЭКО» \\u003cem\\u003e—\\u003c/em\\u003e \\u003c/span\\u003e\\r\\nбезопасный утеплитель\",\"_hero_title\":\"field_hero_hero_title\",\"hero_image\":13,\"_hero_image\":\"field_hero_hero_image\",\"hero_video_id\":\"Y1qQZbTF8iQ\",\"_hero_video_id\":\"field_hero_hero_video_id\",\"hero_text\":\"Экологичный строительный материал, простой в работе и обладающий уникальными тепло и звукоизоляционными свойствами\",\"_hero_text\":\"field_hero_hero_text\",\"hero_url\":\"\",\"_hero_url\":\"field_hero_hero_url\"},\"align\":\"\",\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/about {\"id\":\"block_62eec44b7b0cc\",\"name\":\"acf/about\",\"data\":{\"about_title\":\"Что такое эковата \\u003cspan\\u003e«Ватэко»?\\u003c/span\\u003e\",\"_about_title\":\"field_about_about_title\",\"about_subtitle\":\"Это лёгкий волокнистый материал  серого цвета. \",\"_about_subtitle\":\"field_about_about_subtitle\",\"about_text\":\"Эковата на 82% состоит из переработанной бумаги и на 18% —\\r\\nиз природных антисептиков и огнезащитных компонентов,\\r\\nчто делает её безопасной для людей и окружающей среды.\\r\\n\\r\\nВату используют для бесшовного \\u003cstrong\\u003eутепления домов\\u003c/strong\\u003e,\\r\\n\\u003cstrong\\u003eмансард\\u003c/strong\\u003e, \\u003cstrong\\u003eангаров\\u003c/strong\\u003e и других сооружений.\",\"_about_text\":\"field_about_about_text\",\"about_image\":16,\"_about_image\":\"field_about_about_image\"},\"align\":\"\",\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/products {\"id\":\"block_62eec44d7b0cd\",\"name\":\"acf/products\",\"data\":{\"products_title\":\"Наша продукция\",\"_products_title\":\"field_products_products_title\"},\"align\":\"\",\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/stats {\"id\":\"block_62efa007ecdfa\",\"name\":\"acf/stats\",\"data\":{\"stats_title\":\"Ватэко в цифрах\",\"_stats_title\":\"field_stats_stats_title\",\"stats_list_0_stats_item_title\":\"25 лет\",\"_stats_list_0_stats_item_title\":\"field_stats_stats_list_stats_item_title\",\"stats_list_0_stats_item_text\":\"материал сохраняет \\u003cstrong\\u003eтепло- \\r\\nи звукоизоляционные\\u003c/strong\\u003e свойства\",\"_stats_list_0_stats_item_text\":\"field_stats_stats_list_stats_item_text\",\"stats_list_1_stats_item_title\":\"65 ДБ\",\"_stats_list_1_stats_item_title\":\"field_stats_stats_list_stats_item_title\",\"stats_list_1_stats_item_text\":\"степень \\u003cstrong\\u003eзвукоизоляции\\u003c/strong\\u003e стены, утеплённой эковатой\",\"_stats_list_1_stats_item_text\":\"field_stats_stats_list_stats_item_text\",\"stats_list_2_stats_item_title\":\"На 25%\",\"_stats_list_2_stats_item_title\":\"field_stats_stats_list_stats_item_title\",\"stats_list_2_stats_item_text\":\"\\u003cstrong\\u003eснижает затраты\\u003c/strong\\u003e на обогрев\\r\\nпомещения\",\"_stats_list_2_stats_item_text\":\"field_stats_stats_list_stats_item_text\",\"stats_list\":3,\"_stats_list\":\"field_stats_stats_list\"},\"align\":\"\",\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/calc {\"id\":\"block_62efaa5a354ab\",\"name\":\"acf/calc\",\"data\":{\"calc_title\":\"Рассчитать количество \\u003cspan\\u003eэковаты\\u003c/span\\u003e\",\"_calc_title\":\"field_calc_calc_title\",\"calc_shortcode\":\"[contact-form-7 id=\\u0022174\\u0022 title=\\u0022Рассчитать количество\\u0022 html_class=\\u0022calc__form-calc form form_vertical\\u0022]\",\"_calc_shortcode\":\"field_calc_calc_shortcode\"},\"align\":\"\",\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/advantages {\"id\":\"block_62efb901c8ff8\",\"name\":\"acf/advantages\",\"data\":{\"advantages_title\":\"\\u003cspan\\u003eПреимущества\\u003c/span\\u003e эковаты “Ватэко”\",\"_advantages_title\":\"field_advantages_advantages_title\",\"advantages_icon\":93,\"_advantages_icon\":\"field_advantages_advantages_icon\",\"advantages_icon_1440\":149,\"_advantages_icon_1440\":\"field_advantages_advantages_icon_1440\",\"list_0_list_icon\":94,\"_list_0_list_icon\":\"field_advantages_list_list_icon\",\"list_0_list_title\":\"Воздухопроницаемость\",\"_list_0_list_title\":\"field_advantages_list_list_title\",\"list_0_list_text\":\"Не имеет запаха и не пылит. Не содержит летучих химикатов, не вызывает аллергии.\",\"_list_0_list_text\":\"field_advantages_list_list_text\",\"list_1_list_icon\":95,\"_list_1_list_icon\":\"field_advantages_list_list_icon\",\"list_1_list_title\":\"Экологичность\",\"_list_1_list_title\":\"field_advantages_list_list_title\",\"list_1_list_text\":\"Производится из переработанной макулатуры и имеет невысокую стоимость.\",\"_list_1_list_text\":\"field_advantages_list_list_text\",\"list_2_list_icon\":96,\"_list_2_list_icon\":\"field_advantages_list_list_icon\",\"list_2_list_title\":\"Капиллярная активность\",\"_list_2_list_title\":\"field_advantages_list_list_title\",\"list_2_list_text\":\"Принимает фиксированную форму. Обеспечивает приятный микроклимат, пропуская воздух и не накапливая пара и влаги.\",\"_list_2_list_text\":\"field_advantages_list_list_text\",\"list_3_list_icon\":97,\"_list_3_list_icon\":\"field_advantages_list_list_icon\",\"list_3_list_title\":\"Теплоемкость\",\"_list_3_list_title\":\"field_advantages_list_list_title\",\"list_3_list_text\":\"Обладает теплопроводностью не выше 0,04 единиц. Защищена антисептиками от пожаров, плесени, грызунов и насекомых.\",\"_list_3_list_text\":\"field_advantages_list_list_text\",\"list\":4,\"_list\":\"field_advantages_list\"},\"align\":\"\",\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/certificates {\"id\":\"block_62efee762b0c4\",\"name\":\"acf/certificates\",\"data\":{\"certificates_title\":\"Сертификаты качества\",\"_certificates_title\":\"field_certificates_certificates_title\",\"certificates_slider_0_certificates_image\":101,\"_certificates_slider_0_certificates_image\":\"field_certificates_certificates_slider_certificates_image\",\"certificates_slider_0_certificates_item_title\":\"Сертификат соответствия\",\"_cert