_title\",\"stats_list_0_stats_item_title\":\"25 лет\",\"_stats_list_0_stats_item_title\":\"field_stats_stats_list_stats_item_title\",\"stats_list_0_stats_item_text\":\"материал сохраняет \\u003cstrong\\u003eтепло- \\r\\nи звукоизоляционные\\u003c/strong\\u003e свойства\",\"_stats_list_0_stats_item_text\":\"field_stats_stats_list_stats_item_text\",\"stats_list_1_stats_item_title\":\"65 ДБ\",\"_stats_list_1_stats_item_title\":\"field_stats_stats_list_stats_item_title\",\"stats_list_1_stats_item_text\":\"степень \\u003cstrong\\u003eзвукоизоляции\\u003c/strong\\u003e стены, утеплённой эковатой\",\"_stats_list_1_stats_item_text\":\"field_stats_stats_list_stats_item_text\",\"stats_list_2_stats_item_title\":\"На 25%\",\"_stats_list_2_stats_item_title\":\"field_stats_stats_list_stats_item_title\",\"stats_list_2_stats_item_text\":\"\\u003cstrong\\u003eснижает затраты\\u003c/strong\\u003e на обогрев\\r\\nпомещения\",\"_stats_list_2_stats_item_text\":\"field_stats_stats_list_stats_item_text\",\"stats_list\":3,\"_stats_list\":\"field_stats_stats_list\"},\"align\":\"\",\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/calc {\"id\":\"block_62efaa5a354ab\",\"name\":\"acf/calc\",\"data\":{\"calc_title\":\"Рассчитать количество \\u003cspan\\u003eэковаты\\u003c/span\\u003e\",\"_calc_title\":\"field_calc_calc_title\",\"calc_shortcode\":\"[contact-form-7 id=\\u0022174\\u0022 title=\\u0022Рассчитать количество\\u0022 html_class=\\u0022form form_vertical\\u0022]\",\"_calc_shortcode\":\"field_calc_calc_shortcode\"},\"align\":\"\",\"mode\":\"edit\"} /-->\n\n<!-- wp:acf/advantages {\"id\":\"block_62efb901c8ff8\",\"name\":\"acf/advantages\",\"data\":{\"advantages_title\":\"\\u003cspan\\u003eПреимущества\\u003c/span\\u003e эковаты “Ватэко”\",\"_advantages_title\":\"field_advantages_advantages_title\",\"advantages_icon\":93,\"_advantages_icon\":\"field_advantages_advantages_icon\",\"advantages_icon_1440\":149,\"_advantages_icon_1440\":\"field_advantages_advantages_icon_1440\",\"list_0_list_icon\":94,\"_l